});

function generate_map(frm) {
    if(!frm.doc.الموقع_الخاص_بالمكتب) return;

    try {
        // تحويل GeoJSON إلى إحداثيات
        let geojson = JSON.parse(frm.doc.الموقع_الخاص_بالمكتب);
        let coords = geojson.features[0].geometry.coordinates;
        let lat = coords[1];
        let lng = coords[0];

        let api_key = "YOUR_API_KEY"; // ضع مفتاح Google Maps الخاص بك هنا
        let url = `https://maps.googleapis.com/maps/api/staticmap?center=${lat},${lng}&zoom=15&size=600x300&markers=color:red|${lat},${lng}&key=${api_key}`;

        // جلب الصورة وتحويلها إلى Base64
        fetch(url)
            .then(response => response.blob())
            .then(blob => {
                let reader = new FileReader();
                reader.onloadend = function() {
                    let base64data = reader.result.split(',')[1]; // الحصول على Base64 فقط
                    frm.set_value('map_base64', base64data);
                    frm.save(); // حفظ تلقائي للتحديث
                }
                reader.readAsDataURL(blob);
            })
            .catch(err => {
                frappe.msgprint("خطأ في توليد الخريطة: " + err);
            });
    } catch(e) {
        frappe.msgprint("خطأ في تحليل الموقع: " + e.message);
    }
}

