:: 1. Download
if not exist "%~dp0%INSTALLER_NAME%" (
    echo [1/6] Downloading Installer...
    powershell -Command "[Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12; Invoke-WebRequest -Uri '%DOWNLOAD_URL%' -OutFile '%~dp0%INSTALLER_NAME%'"
)

:: 2. Install
echo [2/6] Installing...
start /wait "" "%~dp0%INSTALLER_NAME%" --silent-install

:: 3. WAITING FOR FILE
echo [3/6] Waiting for installation to finish...
set "RUST_PATH="
for /L %%i in (1,1,20) do (
    if exist "C:\\Program Files\\RustDesk\\rustdesk.exe" (
        set "RUST_PATH=C:\\Program Files\\RustDesk\\rustdesk.exe"
        goto FOUND
    )
    if exist "C:\\Program Files (x86)\\RustDesk\\rustdesk.exe" (
        set "RUST_PATH=C:\\Program Files (x86)\\RustDesk\\rustdesk.exe"
        goto FOUND
    )
    timeout /t 2 /nobreak >nul
)

:FOUND
if "%RUST_PATH%"=="" (
    echo [ERROR] Installation timed out.
    pause
    exit /b
)

:: 4. Stop Service
net stop rustdesk >nul 2>&1

:: 5. Write Config
set "PATH_SERVICE=C:\\Windows\\ServiceProfiles\\LocalService\\AppData\\Roaming\\RustDesk\\config"
set "PATH_USER=%APPDATA%\\RustDesk\\config"
call :WRITE_CONFIG "%PATH_SERVICE%"
call :WRITE_CONFIG "%PATH_USER%"

:: 6. Restart & Set Password
net start rustdesk >nul 2>&1
timeout /t 5 /nobreak > NUL
"%RUST_PATH%" --password "%PLAIN_PASSWORD%"

:: 7. Send ID to ERPNext
echo [6/6] Sending ID to ERPNext...
for /f "tokens=*" %%a in ('"%RUST_PATH%" --get-id') do set "RUST_ID=%%a"

if "!RUST_ID!"=="" (
    echo [ERROR] Could not retrieve ID.
) else (
    echo ID: !RUST_ID!
    powershell -Command "try { [Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12; $res = Invoke-RestMethod -Uri '%ERP_URL%/api/resource/User/%TARGET_ID%' -Method Put -Headers @{ 'Authorization' = 'token %API_KEY%:%API_SECRET%' } -Body (@{ 'remote_id' = '!RUST_ID!' } | ConvertTo-Json) -ContentType 'application/json' -ErrorAction Stop; Write-Host 'SUCCESS' } catch { Write-Host 'FAILURE: ' $_.Exception.Message; $res }"
)

echo.
echo ===================================================
echo   [*] SETUP COMPLETE
echo ===================================================
echo   [~] Cleaning up temporary files...
timeout /t 5 >nul


